Yes, the code can be simplified by using dictionaries instead of multiple if-else statements. Here is the simplified code:

```python
def main():
    value = int(input("Please enter a positive integer < 1000: "))
    print(int_name(value))

def int_name(number):
    part = number
    name = ""

    if part >= 100:
        name += digit_name(part // 100) + " hundred"
        part = part % 100

    if part >= 20:
        name += " " + tens_name(part)
        part = part % 10
    elif part >= 10:
        name += " " + teen_name(part)
        part = 0

    if part > 0:
        name += " " + digit_name(part)

    return name.strip()

def digit_name(digit):
    digits = {
        1: "one",
        2: "two",
        3: "three",
        4: "four",
        5: "five",
        6: "six",
        7: "seven",
        8: "eight",
        9: "nine"
    }
    return digits.get(digit, "")

def teen_name(number):
    teens = {
        10: "ten",
        11: "eleven",
        12: "twelve",
        13: "thirteen",
        14: "fourteen",
        15: "fifteen",
        16: "sixteen",
        17: "seventeen",
        18: "eighteen",
        19: "nineteen"
    }
    return teens.get(number, "")

def tens_name(number):
    tens = {
        20: "twenty",
        30: "thirty",
        40: "forty",
        50: "fifty",
        60: "sixty",
        70: "seventy",
        80: "eighty",
        90: "ninety"
    }
    return tens.get(number, "")

```

In this simplified code:

1. The `digit_name`, `teen_name`, and `tens_name` functions now use dictionaries to store the names corresponding to each digit or number range.
2. The `get` method of dictionaries is used to retrieve the name associated with the input value, with an empty string as the default value if the input value is not found in the dictionary.

